const { Client } = require('magicbell-js/project-client');
const fs = require('fs');

async function main() {
  try {
    const client = new Client({
      projectToken: process.env.MAGICBELL_PROJECT_TOKEN
    });

    const runId = process.env.ZEALT_RUN_ID;
    const magicbellEmail = process.env.MAGICBELL_EMAIL;

    // Construct emails according to the exact instruction:
    // "Construct their email addresses using the MAGICBELL_EMAIL environment variable in the plus format: `${MAGICBELL_EMAIL}+recipient1-${run-id}@gmail.com`"
    const email1 = `${magicbellEmail}+recipient1-${runId}@gmail.com`;
    const email2 = `${magicbellEmail}+recipient2-${runId}@gmail.com`;

    const response = await client.broadcasts.createBroadcast({
      title: `Test Broadcast ${runId}`,
      recipients: [
        { email: email1 },
        { email: email2 }
      ],
      customAttributes: {
        custom_key: "custom_value"
      }
    });

    console.log("Response:", JSON.stringify(response, null, 2));

    // Write the broadcast ID to the log file
    if (response.data && response.data.id) {
      fs.writeFileSync('/home/user/project/output.log', `Broadcast ID: ${response.data.id}\n`);
    } else if (response.id) {
      fs.writeFileSync('/home/user/project/output.log', `Broadcast ID: ${response.id}\n`);
    } else {
      console.log("No ID found in response");
    }
  } catch (err) {
    console.error("Error:", err);
    if (err.response) {
      console.error(err.response.data);
    }
  }
}

main();

